#!/bin/bash\n# Ensure Django logs directory exists.\n# Usage: cd fundvision_backend &amp;&amp; bash setup_logs.sh\n\nset -e\n\nSCRIPT_DIR="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" &amp;>/dev/null &amp;&amp; pwd)"\nlogs_dir="${SCRIPT_DIR}/logs"\nlog_file="${logs_dir}/fundvision.log"\n\necho "Ensuring logs dir: $logs_dir"\nmkdir -p "$logs_dir"\n\nif [ ! -f "$log_file" ]; then\n    touch "$log_file"\n    echo "Created $log_file"\nelse\n    echo "$log_file already exists"\nfi\n\necho "✅ Logs directory ready for Django!"\n
